#include <stdio.h>
#include <stdlib.h>
typedef struct _stack {
    char data;
    struct _stack *link;
} stack;
stack *top; 
int isEmpty()
{
    if (top == NULL) 
    {
        printf("ERROR : Stack is empty. \n");
        return 1;
    }
    return 0;
}
void push(char data)
{
    stack *newNode = malloc(sizeof(stack));
    newNode->data = data;
    newNode->link = top;
    top = newNode;
}

char pop()
{
    if (!isEmpty())
    {
        stack *temp = top;

        char data = top->data;

        top = top->link;

        free(temp);
        return data;
    }
}
char peek()
{
    if (!isEmpty())
    {
        return top->data;
    }
}
void printStack()
{
    if (!isEmpty())
    {
        stack *curr = top;
        while (curr != NULL)
        {
            printf("%c ", curr->data);
            curr = curr->link;
        }
        printf("\n");
    }
}
int main(void)
{

    char check;
    printStack();
    push('A');
    push('B');
    check = peek();
    printf("top : %c\n", check);
    push('C');
    printStack();
    pop();
    push('D');
    check = peek();
    printf("top : %c\n", check);
    push('E');
    push('F');
    printStack();
    pop();
    pop();
    printStack();
    pop();
    return 0;
}```

